import React, { useState, useEffect, useMemo, useRef } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import { LOCATIONS, TRANSLATIONS } from '../constants';
import { Language, LocationType } from '../types';
import { Filter, X } from 'lucide-react';

// Fix for default marker icons in Leaflet with React
// We will use custom DivIcons instead for better styling control
const createCustomIcon = (type: LocationType, isSelected: boolean) => {
  let color = 'bg-blue-500';
  let iconHtml = '<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M20 10c0 6-8 12-8 12s-8-6-8-12a8 8 0 0 1 16 0Z"/><circle cx="12" cy="10" r="3"/></svg>';

  switch(type) {
    case LocationType.EVENT: color = 'bg-red-500'; break;
    case LocationType.BUSINESS: color = 'bg-orange-500'; break;
    case LocationType.BEACH: color = 'bg-cyan-500'; break;
    case LocationType.HISTORY: color = 'bg-amber-700'; break;
    case LocationType.PARK: color = 'bg-green-600'; break;
    default: color = 'bg-blue-600';
  }

  const sizeClass = isSelected ? 'w-10 h-10 ring-4 ring-white' : 'w-8 h-8 ring-2 ring-white';
  const opacityClass = isSelected ? 'opacity-100 z-50' : 'opacity-60 grayscale-[0.5]';

  return L.divIcon({
    className: 'custom-icon',
    html: `<div class="${color} ${sizeClass} rounded-full shadow-lg flex items-center justify-center text-white transition-all duration-300 transform hover:scale-110">${iconHtml}</div>`,
    iconSize: isSelected ? [40, 40] : [32, 32],
    iconAnchor: isSelected ? [20, 40] : [16, 32],
    popupAnchor: [0, -36]
  });
};

interface MapViewProps {
  language: Language;
  focusedLocationId: string | null;
  onFocusComplete: () => void;
}

// Controller component to handle map movement
const MapController = ({ 
  focusedLocationId, 
  onFocusComplete 
}: { 
  focusedLocationId: string | null, 
  onFocusComplete: () => void 
}) => {
  const map = useMap();

  useEffect(() => {
    if (focusedLocationId) {
      const loc = LOCATIONS.find(l => l.id === focusedLocationId);
      if (loc) {
        map.flyTo([loc.coordinates.lat, loc.coordinates.lng], 15, {
          animate: true,
          duration: 1.5
        });

        // Timeout to allow animation to complete before resetting focus state
        const timer = setTimeout(() => {
          onFocusComplete();
        }, 1500);
        return () => clearTimeout(timer);
      }
    }
  }, [focusedLocationId, map, onFocusComplete]);

  return null;
};

const MapView: React.FC<MapViewProps> = ({ language, focusedLocationId, onFocusComplete }) => {
  const [filter, setFilter] = useState<LocationType | 'ALL'>('ALL');
  const [activePopup, setActivePopup] = useState<string | null>(null);

  // If a focusedLocationId comes in, ensure the filter includes it
  useEffect(() => {
    if (focusedLocationId) {
      const loc = LOCATIONS.find(l => l.id === focusedLocationId);
      if (loc) {
        // If we are focused, we show all or ensure the type matches. 
        // Strategy: Switch to ALL to provide context, or switch to specific type?
        // Let's switch to ALL to make sure it's visible if hidden, or keep current if valid.
        // Simple approach: Reset filter to ALL so the user sees the highlighted pin clearly.
        setFilter('ALL');
        setActivePopup(focusedLocationId);
      }
    }
  }, [focusedLocationId]);

  const uniqueTypes = useMemo(() => {
    return Array.from(new Set(LOCATIONS.map(l => l.type)));
  }, []);

  return (
    <div className="flex-1 flex flex-col relative h-full">
      {/* Filter Bar */}
      <div className="absolute top-0 left-0 right-0 z-[1000] p-2 bg-gradient-to-b from-white/90 to-transparent pointer-events-none">
        <div className="flex gap-2 overflow-x-auto no-scrollbar pointer-events-auto pb-2 px-1">
          <button
            onClick={() => setFilter('ALL')}
            className={`flex items-center px-3 py-1.5 rounded-full text-xs font-bold shadow-sm whitespace-nowrap transition-colors ${
              filter === 'ALL' ? 'bg-slate-800 text-white' : 'bg-white text-slate-600'
            }`}
          >
            {filter !== 'ALL' && <X size={12} className="mr-1"/>}
            {TRANSLATIONS.filterAll[language]}
          </button>

          {uniqueTypes.map(type => (
            <button
              key={type}
              onClick={() => setFilter(type)}
              className={`px-3 py-1.5 rounded-full text-xs font-bold shadow-sm whitespace-nowrap transition-all border ${
                filter === type 
                  ? 'bg-blue-600 text-white border-blue-600' 
                  : 'bg-white text-slate-600 border-slate-200'
              }`}
            >
              {type}
            </button>
          ))}
        </div>
      </div>

      <MapContainer 
        center={[-41.8675, -73.8278]} 
        zoom={13} 
        scrollWheelZoom={true} 
        className="w-full h-full z-0"
        zoomControl={false}
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />

        <MapController focusedLocationId={focusedLocationId} onFocusComplete={onFocusComplete} />

        {LOCATIONS.map(location => {
          // Logic for display:
          // If filter is ALL: Show all.
          // If filter is Specific: Highlight specific, Gray out others (or hide? Prompt says "grayed out")
          // To implement "gray out", we change the icon opacity/saturation in createCustomIcon based on selection.

          const isMatch = filter === 'ALL' || filter === location.type;
          // If filtered specifically, we want unmatched items to be "grayed out". 
          // However, Leaflet markers are distinct DOM nodes. 
          // Let's interpret "grayed out" as "less visible styling" or "hidden". 
          // The prompt says: "Selecting different filter options always makes that group be highlighted in the map while the other are grayed out."

          // Let's keep them on map but change icon style.
          const isHighlighted = isMatch;

          // If focused, this one is definitely highlighted
          const isFocused = focusedLocationId === location.id;

          // If focused location is set, we might want to open popup automatically.
          const markerRef = useRef<L.Marker>(null);

          useEffect(() => {
             if (isFocused && markerRef.current) {
                 markerRef.current.openPopup();
             }
          }, [isFocused]);

          return (
            <Marker
              key={location.id}
              position={[location.coordinates.lat, location.coordinates.lng]}
              icon={createCustomIcon(location.type, isHighlighted)}
              ref={markerRef}
              eventHandlers={{
                click: () => setActivePopup(location.id)
              }}
              zIndexOffset={isHighlighted ? 100 : 0}
              opacity={isHighlighted ? 1 : 0.5}
            >
              <Popup className="custom-popup">
                <div className="p-1 min-w-[200px]">
                   <span className="text-[10px] font-bold uppercase text-blue-500 tracking-wider block mb-1">{location.type}</span>
                   <h3 className="font-bold text-base text-slate-800 leading-tight mb-2">{location.name}</h3>
                   {location.description && (
                     <p className="text-sm text-slate-600 mb-2">{location.description}</p>
                   )}
                   {location.link && (
                     <a 
                       href={location.link} 
                       target="_blank" 
                       rel="noopener noreferrer"
                       className="text-xs font-semibold text-blue-600 hover:underline flex items-center"
                     >
                       Google Maps Link &rarr;
                     </a>
                   )}
                </div>
              </Popup>
            </Marker>
          );
        })}
      </MapContainer>
    </div>
  );
};

export default MapView;

