// Map Controller for FlyTo animation
const MapController = ({ 
  focusedLocationId, 
  onFocusComplete 
}: { 
  focusedLocationId: string | null, 
  onFocusComplete: () => void 
}) => {
  const map = useMap();

  useEffect(() => {
    if (focusedLocationId) {
      const loc = LOCATIONS.find(l => l.id === focusedLocationId);
